  1	import * as React from 'react';
  2	import TimesIcon from '@patternfly/react-icons/dist/esm/icons/times-icon';
  3	import {
  4	  Select,
  5	  SelectList,
  6	  SelectOption,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  MenuToggleStatus,
 10	  TextInputGroup,
 11	  TextInputGroupMain,
 12	  TextInputGroupUtilities,
 13	  Button,
 14	} from '@patternfly/react-core';
 15	import { useCustomTranslation } from '../useCustomTranslationHook';
 16	
 17	export const SingleSelectDropdown: React.FC<SingleSelectDropdownProps> = ({
 18	  onChange,
 19	  selectOptions,
 20	  selectedKey = '',
 21	  validated,
 22	  className,
 23	  valueLabelMap,
 24	  ...props
 25	}) => {
 26	  const { t } = useCustomTranslation();
 27	
 28	  const [isOpen, setIsOpen] = React.useState(false);
 29	  const [newOptions, setNewOptions] = React.useState<JSX.Element[]>([]);
 30	  const [status, setStatus] = React.useState<MenuToggleStatus>();
 31	  const [filterValue, setFilterValue] = React.useState('');
 32	  const [inputValue, setInputValue] = React.useState('');
 33	  const [newOptionVal, setNewOptionVal] = React.useState('');
 34	  const DISABLED = '__disabled__';
 35	
 36	  React.useEffect(() => {
 37	    if (selectedKey) {
 38	      const matchedOption = React.Children.toArray(selectOptions).find(
 39	        (opt: any) => opt.props?.value === selectedKey
 40	      ) as React.ReactElement | undefined;
 41	
 42	      if (matchedOption) {
 43	        setInputValue(String(matchedOption.props.children));
 44	      } else {
 45	        setInputValue(selectedKey);
 46	      }
 47	    } else {
 48	      setInputValue('');
 49	    }
 50	  }, [selectedKey, selectOptions]);
 51	
 52	  React.useEffect(() => {
 53	    let derivedValidated = validated === 'error' ? 'danger' : validated;
 54	    setStatus(
 55	      derivedValidated && derivedValidated !== 'default'
 56	        ? (derivedValidated as MenuToggleStatus)
 57	        : undefined
 58	    );
 59	  }, [validated]);
 60	
 61	  React.useEffect(() => {
 62	    if (filterValue) {
 63	      setNewOptionVal(filterValue);
 64	    }
 65	  }, [filterValue]);
 66	
 67	  const filteredOptions = React.useMemo(() => {
 68	    let options = selectOptions;
 69	    const lowerValue = filterValue.toLowerCase();
 70	    if (props.hasInlineFilter && filterValue) {
 71	      options = selectOptions.filter((option) =>
 72	        String(option.props.children).toLowerCase().includes(lowerValue)
 73	      );
 74	
 75	      const exactMatchExists = selectOptions.some(
 76	        (option) => String(option.props.children).toLowerCase() === lowerValue
 77	      );
 78	
 79	      if (options.length === 0) {
 80	        if (props.isCreatable && filterValue.trim() && !exactMatchExists) {
 81	          options = [
 82	            <SelectOption key={filterValue} value={filterValue}>
 83	              {t('Create "{{filterValue}}"', { filterValue })}
 84	            </SelectOption>,
 85	          ];
 86	        } else {
 87	          options = [
 88	            <SelectOption key={DISABLED} value={DISABLED} isDisabled>
 89	              {t('No option found')}
 90	            </SelectOption>,
 91	          ];
 92	        }
 93	      } else if (props.isCreatable && filterValue.trim() && !exactMatchExists) {
 94	        options = [
 95	          <SelectOption key={filterValue} value={filterValue}>
 96	            {t('Create "{{filterValue}}"', { filterValue })}
 97	          </SelectOption>,
 98	          ...options,
 99	        ];
100	      }
101	    }
102	
103	    return options;
104	  }, [filterValue, props.hasInlineFilter, props.isCreatable, selectOptions, t]);
105	
106	  const allOptions =
107	    newOptions.length > 0
108	      ? filteredOptions.concat(newOptions)
109	      : filteredOptions;
110	
111	  const onSelect = React.useCallback(
112	    (_event: React.MouseEvent | React.ChangeEvent, selection: string) => {
113	      /**
114	       * For case when the dropdownitem that we want to show on UI (label)
115	       * and its corresponding value that we want to store in the redux-state is different.
116	       * e.g: OSDSizeDropdown
117	       */
118	      const value = valueLabelMap
119	        ? Object.keys(valueLabelMap).find(
120	            (key) => valueLabelMap[key] === selection
121	          )
122	        : selection;
123	      if (!value) return;
124	
125	      if (value === newOptionVal) {
126	        const newValue = newOptionVal;
127	        if (newValue) {
128	          const newOption = (
129	            <SelectOption key={newValue} value={newValue}>
130	              {newValue}
131	            </SelectOption>
132	          );
133	          setNewOptions((prev) => [...prev, newOption]);
134	          onChange(newValue);
135	          setInputValue(newValue);
136	          setFilterValue('');
137	          setIsOpen(false);
138	        }
139	        return;
140	      }
141	
142	      const stringValue = String(value);
143	
144	      const matchedOption = React.Children.toArray(selectOptions).find(
145	        (opt: any) => opt.props?.value === stringValue
146	      ) as React.ReactElement | undefined;
147	
148	      const displayLabel = matchedOption
149	        ? String(matchedOption.props.children)
150	        : stringValue;
151	
152	      onChange(stringValue);
153	      setInputValue(displayLabel);
154	      setIsOpen(false);
155	      setFilterValue('');
156	    },
157	    [valueLabelMap, onChange, setIsOpen, selectOptions, newOptionVal]
158	  );
159	  const onTextInputChange = (
160	    _e: React.FormEvent<HTMLInputElement>,
161	    value: string
162	  ) => {
163	    setFilterValue(value);
164	    setInputValue(value);
165	  };
166	
167	  const onClearButtonClick = () => {
168	    setFilterValue('');
169	    setInputValue('');
170	    onChange('');
171	  };
172	
173	  const onInputClick = () => {
174	    if (!isOpen) {
175	      setIsOpen(true);
176	    } else if (!inputValue) {
177	      setIsOpen(false);
178	    }
179	  };
180	
181	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => {
182	    if (props.hasInlineFilter || props.isCreatable) {
183	      return (
184	        <MenuToggle
185	          ref={toggleRef}
186	          variant="typeahead"
187	          aria-label={props['aria-label'] || t('Options menu')}
188	          isExpanded={isOpen}
189	          isDisabled={props.isDisabled}
190	          status={status}
191	          onClick={() => setIsOpen((prev) => !prev)}
192	          className={className}
193	        >
194	          <TextInputGroup isPlain>
195	            <TextInputGroupMain
196	              value={inputValue}
197	              onChange={onTextInputChange}
198	              onClick={onInputClick}
199	              placeholder={props.placeholderText || t('Select options')}
200	              autoComplete="off"
201	            />
202	            <TextInputGroupUtilities
203	              {...(!inputValue ? { style: { display: 'none' } } : {})}
204	            >
205	              <Button
206	                variant="plain"
207	                onClick={onClearButtonClick}
208	                aria-label={t('Clear input')}
209	                icon={<TimesIcon />}
210	              />
211	            </TextInputGroupUtilities>
212	          </TextInputGroup>
213	        </MenuToggle>
214	      );
215	    }
216	
217	    return (
218	      <MenuToggle
219	        ref={toggleRef}
220	        aria-label={props['aria-label'] || t('Typeahead single select')}
221	        onClick={() => setIsOpen((prev) => !prev)}
222	        isExpanded={isOpen}
223	        isDisabled={props.isDisabled}
224	        status={status}
225	        className={className}
226	      >
227	        {inputValue || props.placeholderText || t('Select options')}
228	      </MenuToggle>
229	    );
230	  };
231	
232	  return (
233	    <div className="test" data-test={props['data-test']}>
234	      <Select
235	        id={props.id}
236	        isOpen={isOpen}
237	        selected={selectedKey}
238	        onSelect={onSelect}
239	        onOpenChange={(open) => setIsOpen(open)}
240	        toggle={toggle}
241	        shouldFocusToggleOnSelect
242	        popperProps={{ width: 'trigger' }}
243	      >
244	        <SelectList>{allOptions}</SelectList>
245	      </Select>
246	    </div>
247	  );
248	};
249	
250	export type SingleSelectDropdownProps = {
251	  id?: string;
252	  selectedKey?: string;
253	  placeholderText?: string;
254	  valueLabelMap?: { [key: string]: string };
255	  className?: string;
256	  selectOptions: JSX.Element[];
257	  onChange: (selected: string) => void;
258	  'data-test'?: string;
259	  onFilter?: (
260	    e: React.ChangeEvent<HTMLInputElement> | React.MouseEvent,
261	    value: string
262	  ) => void;
263	  hasInlineFilter?: boolean;
264	  isDisabled?: boolean;
265	  validated?: 'success' | 'warning' | 'error' | 'default';
266	  required?: boolean;
267	  isCreatable?: boolean;
268	  'aria-label'?: string;
269	};

